import {
  useRef,
  useState,
  useCallback,
  useEffect,
  useLayoutEffect,
  useMemo,
} from "react";
import { useAppDispatch, useAppSelector } from "./redux/hooks";
import {
  setFogGateWarp,
  removeFogGateWarp,
  setBossDefeated,
  startNewRun,
} from "./redux";
import { getRegionLayouts } from "./Constants/canvasLayout";

function sideRefKey(ref) {
  return `${ref.fogGateId}:${ref.side}`;
}

/** Red is reserved for connections in progress (unresolved); resolved connections never use it. */
const CONNECTION_IN_PROGRESS_COLOR = "#ef4444";

/** High-contrast cable palette for dark background (crafty / Reason-style). No red—reserved for in-progress. */
const CONNECTION_PALETTE = [
  "#4ade80",
  "#a78bfa",
  "#fb923c",
  "#2dd4bf",
  "#facc15",
  "#22d3ee",
  "#f472b6",
  "#60a5fa",
  "#c084fc",
  "#34d399",
  "#06b6d4",
  "#fbbf24",
  "#38bdf8",
];

/** Quadratic curve control point so the line bends and reads clearly. */
function getCurveControlPoint(x1, y1, x2, y2) {
  const midX = (x1 + x2) / 2;
  const midY = (y1 + y2) / 2;
  const dx = x2 - x1;
  const dy = y2 - y1;
  const dist = Math.hypot(dx, dy) || 1;
  const curve = Math.min(40, dist * 0.3);
  let perpX = (-dy / dist) * curve;
  let perpY = (dx / dist) * curve;
  if (dx < 0) {
    perpX = -perpX;
    perpY = -perpY;
  }
  return { cx: midX + perpX, cy: midY + perpY };
}

export default function FogGateCanvas() {
  const dispatch = useAppDispatch();
  const run = useAppSelector((s) => s.run.run);
  const wrapRef = useRef(null);
  const containerRef = useRef(null);
  const handleRefs = useRef(new Map());
  const [handlePositions, setHandlePositions] = useState(new Map());
  const [containerRect, setContainerRect] = useState({ width: 1, height: 1 });
  const [dragging, setDragging] = useState(null);
  const [dragPos, setDragPos] = useState(null);
  const [hoverTarget, setHoverTarget] = useState(null);
  const [hoveredWarpIndex, setHoveredWarpIndex] = useState(null);
  const [modifierHeld, setModifierHeld] = useState(false);
  const [toastMessage, setToastMessage] = useState(null);
  const toastTimeoutRef = useRef(null);

  const showToast = useCallback((message) => {
    if (toastTimeoutRef.current) clearTimeout(toastTimeoutRef.current);
    setToastMessage(message);
    toastTimeoutRef.current = setTimeout(() => {
      setToastMessage(null);
      toastTimeoutRef.current = null;
    }, 4000);
  }, []);

  useLayoutEffect(() => {
    const onKeyDown = (e) => {
      if (e.metaKey || e.ctrlKey) setModifierHeld(true);
    };
    const onKeyUp = (e) => {
      if (!e.metaKey && !e.ctrlKey) setModifierHeld(false);
    };
    window.addEventListener("keydown", onKeyDown);
    window.addEventListener("keyup", onKeyUp);
    return () => {
      window.removeEventListener("keydown", onKeyDown);
      window.removeEventListener("keyup", onKeyUp);
    };
  }, []);

  useEffect(() => {
    return () => {
      if (toastTimeoutRef.current) clearTimeout(toastTimeoutRef.current);
    };
  }, []);

  const layouts = getRegionLayouts();
  const warps = useMemo(() => run?.fogGateWarps ?? [], [run?.fogGateWarps]);

  const getConnectionColorForHandle = useCallback(
    (fogGateId, side) => {
      const idx = warps.findIndex(
        (w) =>
          (w.from.fogGateId === fogGateId && w.from.side === side) ||
          (w.to.fogGateId === fogGateId && w.to.side === side),
      );
      if (idx < 0) return null;
      const w = warps[idx];
      const colorIndex = w.colorIndex ?? idx;
      return CONNECTION_PALETTE[colorIndex % CONNECTION_PALETTE.length];
    },
    [warps],
  );

  const getConnectionCountForHandle = useCallback(
    (fogGateId, side) =>
      warps.filter(
        (w) =>
          (w.from.fogGateId === fogGateId && w.from.side === side) ||
          (w.to.fogGateId === fogGateId && w.to.side === side),
      ).length,
    [warps],
  );

  const potentialConnectionColor = CONNECTION_IN_PROGRESS_COLOR;

  const measureHandles = useCallback(() => {
    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();
    const next = new Map();
    handleRefs.current.forEach((el, key) => {
      if (!el) return;
      const r = el.getBoundingClientRect();
      next.set(key, {
        x: r.left - rect.left + r.width / 2,
        y: r.top - rect.top + r.height / 2,
      });
    });
    setHandlePositions(next);
    setContainerRect({ width: rect.width, height: rect.height });
  }, []);

  const scheduleMeasure = useCallback(() => {
    requestAnimationFrame(() => {
      measureHandles();
    });
  }, [measureHandles]);

  useLayoutEffect(() => {
    measureHandles();
    const container = containerRef.current;
    if (!container) return;
    const ro = new ResizeObserver(scheduleMeasure);
    ro.observe(container);
    const onWindowResize = () => scheduleMeasure();
    window.addEventListener("resize", onWindowResize);
    return () => {
      ro.disconnect();
      window.removeEventListener("resize", onWindowResize);
    };
  }, [measureHandles, scheduleMeasure]);

  useLayoutEffect(() => {
    if (run) scheduleMeasure();
  }, [run, scheduleMeasure]);

  const setHandleRef = useCallback((key, el) => {
    if (el) handleRefs.current.set(key, el);
    else handleRefs.current.delete(key);
  }, []);

  const completeConnectionTo = useCallback(
    (targetFogGateId, targetSide) => {
      if (!dragging || !run) return;
      const from = {
        fogGateId: dragging.fogGateId,
        side: dragging.side,
      };
      const to = { fogGateId: targetFogGateId, side: targetSide };
      const targetConnectionCount = getConnectionCountForHandle(
        targetFogGateId,
        targetSide,
      );
      if (targetConnectionCount >= 2) {
        setDragging(null);
        setDragPos(null);
        setHoverTarget(null);
        return;
      }
      if (from.fogGateId !== to.fogGateId || from.side !== to.side) {
        dispatch(setFogGateWarp({ from, to }));
      }
      setDragging(null);
      setDragPos(null);
      setHoverTarget(null);
    },
    [dragging, run, dispatch, getConnectionCountForHandle],
  );

  const onHandlePointerDown = useCallback(
    (e, fogGateId, side) => {
      e.preventDefault();
      if (!run) return;
      if (e.metaKey || e.ctrlKey) {
        dispatch(removeFogGateWarp({ fogGateId, side }));
        return;
      }
      if (getConnectionCountForHandle(fogGateId, side) >= 2) {
        showToast(
          "That fog gate already has two connections. Delete a connection with command/ctrl-click to reconnect the gate.",
        );
        return;
      }
      if (
        dragging &&
        dragging.fogGateId === fogGateId &&
        dragging.side === side
      ) {
        setDragging(null);
        setDragPos(null);
        setHoverTarget(null);
        return;
      }
      if (
        dragging &&
        (dragging.fogGateId !== fogGateId || dragging.side !== side)
      ) {
        completeConnectionTo(fogGateId, side);
        return;
      }
      setDragging({ fogGateId, side });
      wrapRef.current?.setPointerCapture(e.pointerId);
      const container = containerRef.current;
      if (container) {
        const rect = container.getBoundingClientRect();
        setDragPos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
      }
    },
    [
      run,
      dispatch,
      dragging,
      completeConnectionTo,
      getConnectionCountForHandle,
      showToast,
    ],
  );

  const onHandlePointerUp = useCallback(
    (e, targetFogGateId, targetSide) => {
      if (!dragging) return;
      if (
        dragging.fogGateId === targetFogGateId &&
        dragging.side === targetSide
      ) {
        return;
      }
      completeConnectionTo(targetFogGateId, targetSide);
    },
    [dragging, completeConnectionTo],
  );

  const onPointerMove = useCallback(
    (e) => {
      if (dragging && containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        setDragPos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
      }
    },
    [dragging],
  );

  const onPointerUpGlobal = useCallback(
    (e) => {
      if (!dragging) return;
      const el = e.target && document.elementFromPoint(e.clientX, e.clientY);
      const handle = el?.closest?.(".fog-canvas-handle");
      if (handle?.dataset?.fogGateId != null && handle?.dataset?.side != null) {
        const targetFogGateId = handle.dataset.fogGateId;
        const targetSide = handle.dataset.side;
        if (
          dragging.fogGateId === targetFogGateId &&
          dragging.side === targetSide
        ) {
          return;
        }
        completeConnectionTo(targetFogGateId, targetSide);
        return;
      }
      setDragging(null);
      setDragPos(null);
      setHoverTarget(null);
    },
    [dragging, completeConnectionTo],
  );

  if (!run) {
    return (
      <div className="fog-canvas-empty">
        <p>Start a run to wire fog gates.</p>
        <button
          type="button"
          className="btn btn-primary"
          onClick={() => dispatch(startNewRun())}
        >
          Start run
        </button>
      </div>
    );
  }

  const { width: svgW, height: svgH } = containerRect;

  return (
    <div
      ref={wrapRef}
      className="fog-canvas-wrap"
      onPointerMove={onPointerMove}
      onPointerLeave={onPointerUpGlobal}
      onPointerUp={onPointerUpGlobal}
      onPointerCancel={onPointerUpGlobal}
    >
      <div ref={containerRef} className="fog-canvas-inner">
        <svg
          className="fog-canvas-lines"
          width={svgW}
          height={svgH}
          viewBox={`0 0 ${svgW} ${svgH}`}
          preserveAspectRatio="none"
          style={{ touchAction: "none" }}
        >
          <g className="fog-canvas-warps" style={{ pointerEvents: "none" }}>
            {warps.map((warp, i) => {
              const fromPos = handlePositions.get(sideRefKey(warp.from));
              const toPos = handlePositions.get(sideRefKey(warp.to));
              if (!fromPos || !toPos) return null;
              const { cx, cy } = getCurveControlPoint(
                fromPos.x,
                fromPos.y,
                toPos.x,
                toPos.y,
              );
              const colorIndex = warp.colorIndex ?? i;
              const strokeColor =
                CONNECTION_PALETTE[colorIndex % CONNECTION_PALETTE.length];
              const isHoveredWithModifier =
                hoveredWarpIndex === i && modifierHeld;
              return (
                <path
                  key={`${sideRefKey(warp.from)}-${i}`}
                  d={`M ${fromPos.x} ${fromPos.y} Q ${cx} ${cy} ${toPos.x} ${toPos.y}`}
                  className={`fog-canvas-warp-line${isHoveredWithModifier ? " fog-canvas-warp-line--delete-hover" : ""}`}
                  fill="none"
                  stroke={isHoveredWithModifier ? "#dc2626" : strokeColor}
                  strokeWidth={isHoveredWithModifier ? 4 : 2.5}
                  style={{
                    pointerEvents: "stroke",
                    cursor: modifierHeld ? "pointer" : "default",
                  }}
                  onPointerEnter={() => setHoveredWarpIndex(i)}
                  onPointerLeave={() => setHoveredWarpIndex(null)}
                  onClick={(e) => {
                    if (e.metaKey || e.ctrlKey) {
                      e.preventDefault();
                      dispatch(removeFogGateWarp(warp.from));
                    }
                  }}
                  title={
                    modifierHeld ? "⌘/Ctrl+click to delete connection" : null
                  }
                />
              );
            })}
            {dragging &&
              dragPos &&
              (() => {
                const fromPos = handlePositions.get(
                  sideRefKey({
                    fogGateId: dragging.fogGateId,
                    side: dragging.side,
                  }),
                );
                if (!fromPos) return null;
                const { cx, cy } = getCurveControlPoint(
                  fromPos.x,
                  fromPos.y,
                  dragPos.x,
                  dragPos.y,
                );
                return (
                  <path
                    d={`M ${fromPos.x} ${fromPos.y} Q ${cx} ${cy} ${dragPos.x} ${dragPos.y}`}
                    className="fog-canvas-warp-line fog-canvas-warp-line--preview"
                    fill="none"
                    stroke={potentialConnectionColor}
                    strokeWidth={2.5}
                    strokeDasharray="5 4"
                  />
                );
              })()}
          </g>
        </svg>

        <div className="fog-canvas-regions">
          {layouts.map((region) => (
            <div
              key={region.areaId}
              className="fog-canvas-region"
              style={{
                "--region-color": region.color,
              }}
            >
              <div className="fog-canvas-region-name">{region.areaName}</div>
              <div className="fog-canvas-gates">
                {region.gates.map((gate) => (
                  <div key={gate.id} className="fog-canvas-gate">
                    <span className="fog-canvas-gate-name">
                      {gate.name ?? gate.id}
                      {gate.bossId && (
                        <button
                          type="button"
                          className={`fog-canvas-boss-toggle${run?.bossesDefeated?.includes(gate.bossId) ? " fog-canvas-boss-toggle--defeated" : ""}`}
                          onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            if (!run) return;
                            dispatch(
                              setBossDefeated({
                                bossId: gate.bossId,
                                defeated: !run.bossesDefeated.includes(
                                  gate.bossId,
                                ),
                              }),
                            );
                          }}
                          title={
                            run?.bossesDefeated?.includes(gate.bossId)
                              ? "Mark boss as not defeated"
                              : "Mark boss as defeated"
                          }
                          aria-label={
                            run?.bossesDefeated?.includes(gate.bossId)
                              ? "Boss defeated (click to undo)"
                              : "Mark boss defeated"
                          }
                        >
                          💀
                        </button>
                      )}
                    </span>
                    <div className="fog-canvas-handles">
                      {["front", "back"].map((side) => {
                        const hasSide =
                          (side === "front" && gate.frontNodeId != null) ||
                          (side === "back" && gate.backNodeId != null);
                        if (!hasSide) {
                          return (
                            <span
                              key={side}
                              className="fog-canvas-handle-spacer"
                              aria-hidden
                            />
                          );
                        }
                        const isSource =
                          dragging &&
                          dragging.fogGateId === gate.id &&
                          dragging.side === side;
                        const isHoverTarget =
                          dragging &&
                          hoverTarget?.fogGateId === gate.id &&
                          hoverTarget?.side === side &&
                          !isSource;
                        const connectionColor = getConnectionColorForHandle(
                          gate.id,
                          side,
                        );
                        const connectionCount = getConnectionCountForHandle(
                          gate.id,
                          side,
                        );
                        const isFull = connectionCount >= 2;
                        const isDropBlocked = isHoverTarget && isFull;
                        const displayColor =
                          isHoverTarget && !isDropBlocked
                            ? potentialConnectionColor
                            : (connectionColor ??
                              (side === "front"
                                ? "rgba(255,255,255,0.9)"
                                : "rgba(200,200,255,0.9)"));
                        return (
                          <button
                            key={side}
                            type="button"
                            data-fog-gate-id={gate.id}
                            data-side={side}
                            className={`fog-canvas-handle fog-canvas-handle--${side}${
                              connectionColor
                                ? " fog-canvas-handle--connected"
                                : ""
                            }${isSource ? " fog-canvas-handle--source" : ""}${
                              isHoverTarget && !isDropBlocked
                                ? " fog-canvas-handle--hover-target"
                                : ""
                            }${isDropBlocked ? " fog-canvas-handle--drop-blocked" : ""}${isFull ? " fog-canvas-handle--full" : ""}`}
                            ref={(el) =>
                              setHandleRef(
                                sideRefKey({ fogGateId: gate.id, side }),
                                el,
                              )
                            }
                            style={{ "--handle-color": displayColor }}
                            onPointerDown={(e) =>
                              onHandlePointerDown(e, gate.id, side)
                            }
                            onPointerUp={(e) =>
                              onHandlePointerUp(e, gate.id, side)
                            }
                            onPointerEnter={() =>
                              dragging &&
                              setHoverTarget({ fogGateId: gate.id, side })
                            }
                            onPointerLeave={() =>
                              dragging && setHoverTarget(null)
                            }
                            title={
                              isFull
                                ? `${side === "front" ? "Front" : "Back"} (⌘/Ctrl+click to delete connections)`
                                : `${side === "front" ? "Front" : "Back"} (click or drag to connect, ⌘/Ctrl+click to delete)`
                            }
                            aria-label={`${gate.name ?? gate.id} ${side}`}
                          />
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
      {toastMessage && (
        <div className="fog-canvas-toast" role="status" aria-live="polite">
          {toastMessage}
        </div>
      )}
    </div>
  );
}
